const fs = require\('fs'\);
const path = require\('path'\);

const cookiePath = path.join\(process.env.HOME, 'Library', 'Containers', 'com.apple.Safari', 'Data', 'Library', 'Cookies', 'Cookies.binarycookies'\);
const cookieData = fs.readFileSync\(cookiePath\);

// 解析 cookie
function parseBinaryCookies\(buffer\) {
  const cookies = [];
  try {
    const numCookies = buffer.readUInt32BE\(4\);
    console.log\('Cookie count:', numCookies\);
    let offset = 8;

    for \(let i = 0; i < numCookies && offset < buffer.length; i++\) {
      try {
        const cookieSize = buffer.readUInt32BE\(offset\);
        const cookieDataSlice = buffer.slice\(offset + 4, offset + 4 + cookieSize\);

        let pos = 0;
        const flags = cookieDataSlice.readUInt8\(pos\); pos += 4;
        const domainLen = cookieDataSlice.readUInt8\(pos\); pos += 1;
        const pathLen = cookieDataSlice.readUInt8\(pos\); pos += 1;

        // 读取 domain
        const domain = cookieDataSlice.slice\(pos, pos + domainLen\).toString\('utf8'\); pos += domainLen;
        // 读取 name
        const nameLen = cookieDataSlice.readUInt8\(pos\); pos += 1;
        const name = cookieDataSlice.slice\(pos, pos + nameLen\).toString\('utf8'\); pos += nameLen;
        // 读取 value
        const valueLen = cookieDataSlice.readUInt8\(pos\); pos += 1;
        const value = cookieDataSlice.slice\(pos, pos + valueLen\).toString\('utf8'\);

        if \(domain.includes\('kimi.com'\) || name === 'kimi-auth'\) {
          console.log\('Found kimi cookie:', name, domain\);
          cookies.push\({ name, value, domain }\);
        }

        offset += 4 + cookieSize;
      } catch \(e\) {
        console.log\('Error parsing cookie', i, e.message\);
        break;
      }
    }
  } catch \(e\) {
    console.error\('Error:', e.message\);
  }
  return cookies;
}

const cookies = parseBinaryCookies\(cookieData\);
console.log\('Found kimi cookies:', cookies.length\);
")

