  const data = fs.readFileSync\(cookiePath\);
  console.log\('Size:', data.length\);

  // 解析 binary cookies
  function parseBinaryCookies\(buffer\) {
    const cookies = [];
    try {
      const magic = buffer.toString\('binary', 0, 4\);
      if \(magic !== 'cook'\) return cookies;

      const numCookies = buffer.readUInt32BE\(4\);
      let offset = 8;

      for \(let i = 0; i < numCookies && offset < buffer.length; i++\) {
        try {
          const cookieSize = buffer.readUInt32BE\(offset\);
          const cookieDataSlice = buffer.slice\(offset + 4, offset + 4 + cookieSize\);

          let pos = 0;
          cookieDataSlice.readUInt8\(pos\); pos += 4;
          const domainLen = cookieDataSlice.readUInt8\(pos\); pos += 1;
          const pathLen = cookieDataSlice.readUInt8\(pos\); pos += 1;

          const domain = cookieDataSlice.slice\(pos, pos + domainLen\).toString\('utf8'\); pos += domainLen;
          const nameLen = cookieDataSlice.readUInt8\(pos\); pos += 1;
          const name = cookieDataSlice.slice\(pos, pos + nameLen\).toString\('utf8'\); pos += nameLen;
          const valueLen = cookieDataSlice.readUInt8\(pos\); pos += 1;
          const value = cookieDataSlice.slice\(pos, pos + valueLen\).toString\('utf8'\);

          cookies.push\({ name, domain, value: value.substring\(0, 50\) + \(value.length > 50 ? '...' : ''\) }\);
          offset += 4 + cookieSize;
        } catch \(e\) {
          break;
        }
      }
    } catch \(e\) {}
    return cookies;
  }

  const cookies = parseBinaryCookies\(data\);
  console.log\('Total:', cookies.length\);
  cookies.forEach\(c => console.log\(c.name, '|', c.domain\)\);
}
")

